module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

	reg CLK_50_reg, CLK_10_reg, CLK_1_reg;
	reg [3:0] cnt_10;
	reg [6:0] cnt_100;

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			CLK_50_reg <= 1'b0;
		end
		else begin
			CLK_50_reg <= ~CLK_50_reg;
		end
	end

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			cnt_10 <= 4'd0;
			CLK_10_reg <= 1'b0;
		end
		else begin
			if(cnt_10 == 4'd4) begin
				CLK_10_reg <= ~CLK_10_reg;
				cnt_10 <= 4'd0;
			end
			else begin
				cnt_10 <= cnt_10 + 1;
			end
		end
	end

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			cnt_100 <= 7'd0;
			CLK_1_reg <= 1'b0;
		end
		else begin
			if(cnt_100 == 7'd49) begin
				CLK_1_reg <= ~CLK_1_reg;
				cnt_100 <= 7'd0;
			end
			else begin
				cnt_100 <= cnt_100 + 1;
			end
		end
	end

	assign CLK_50 = CLK_50_reg;
	assign CLK_10 = CLK_10_reg;
	assign CLK_1 = CLK_1_reg;

endmodule
